import React from "react";

const Experience = () => {
  const jobs = [
    {
      role: "Co-op Software Developer",
      company: "Greenovate",
      date: "May 2023 – Aug 2023",
      details: [
        "Developed and maintained a React-based website for carbon-negative initiatives.",
        "Translated requirements into UI mockups using Figma.",
        "Improved UX, increasing engagement on key sections.",
      ],
    },
    {
      role: "Sales Associate",
      company: "ZARA",
      date: "Sept 2022 – Present",
      details: [
        "Maintained operational standards in high-volume retail.",
        "Delivered strong customer service under pressure.",
      ],
    },
    {
      role: "Communication Representative",
      company: "WITS, Dalhousie University",
      date: "2022 – 2023",
      details: [
        "Authored documentation for events & projects.",
        "Coordinated stakeholder meetings and timelines.",
      ],
    },
  ];

  return (
    <section id="experience" className="py-20 px-6">
      <h2 className="text-3xl font-bold text-center mb-8">Experience</h2>
      <div className="space-y-8 max-w-4xl mx-auto">
        {jobs.map((job, idx) => (
          <div key={idx} className="bg-white shadow p-6 rounded-lg">
            <h3 className="text-xl font-semibold text-purple-700">
              {job.role} – {job.company}
            </h3>
            <p className="text-gray-500 text-sm mb-3">{job.date}</p>
            <ul className="list-disc pl-6 space-y-1 text-gray-700">
              {job.details.map((point, i) => (
                <li key={i}>{point}</li>
              ))}
            </ul>
          </div>
        ))}
      </div>
    </section>
  );
};

export default Experience;
